 79→fn toggle_window(window: &tauri::WebviewWindow) {
 80→    let visible = window.is_visible().unwrap_or(false);
 81→    let focused = window.is_focused().unwrap_or(false);
 82→
 83→    if visible && focused {
 84→        if let Err(e) = window.hide() {
 85→            eprintln!("failed to hide window: {e}");
 86→        }
 87→    } else if visible {
 88→        show_and_focus(window);
 89→    } else {
 90→        show_and_focus(window);
 91→    }
 92→}
