119→fn start_clipboard_monitor(app_handle: tauri::AppHandle) {
120→    use tauri_plugin_clipboard_manager::ClipboardExt;
121→
122→    std::thread::spawn(move || {
123→        let mut last_text = String::new();
124→
125→        loop {
126→            std::thread::sleep(Duration::from_millis(500));
127→
128→            let text = match app_handle.clipboard().read_text() {
129→                Ok(t) => t,
130→                Err(_) => continue,
131→            };
132→
133→            if text.is_empty() || text == last_text {
134→                continue;
135→            }
136→            last_text = text.clone();
137→
138→            let content_type = detect_content_type(&text);
139→
140→            let elapsed = std::time::SystemTime::now()
141→                .duration_since(std::time::UNIX_EPOCH)
142→                .unwrap_or_default();
143→            let timestamp_ms = elapsed.as_secs() * 1000 + elapsed.subsec_millis() as u64;
144→
145→            let payload = serde_json::json!({
146→                "content": text,
147→                "contentType": content_type,
148→                "timestamp": timestamp_ms,
149→            });
150→
151→            if let Err(e) = app_handle.emit("clipboard-changed", payload) {
152→                eprintln!("failed to emit clipboard-changed: {e}");
153→            }
154→        }
155→    });
156→}
