335→#[tauri::command]
336→fn reveal_in_finder(path: String) -> Result<(), String> {
337→    let p = std::path::Path::new(&path);
338→    if !is_path_within_home(p) {
339→        return Err(format!("path not allowed: {path}"));
340→    }
341→
342→    #[cfg(target_os = "macos")]
343→    {
344→        let output = std::process::Command::new("open")
345→            .arg("-R")
346→            .arg(&path)
347→            .output()
348→            .map_err(|e| format!("failed to reveal {path}: {e}"))?;
349→        if !output.status.success() {
350→            let stderr = String::from_utf8_lossy(&output.stderr);
351→            return Err(format!("failed to reveal {path}: {stderr}"));
352→        }
353→        return Ok(());
354→    }
355→
356→    #[cfg(target_os = "windows")]
357→    {
358→        let output = std::process::Command::new("explorer")
359→            .arg(format!("/select,{}", &path))
360→            .output()
361→            .map_err(|e| format!("failed to reveal {path}: {e}"))?;
362→        if !output.status.success() {
363→            let stderr = String::from_utf8_lossy(&output.stderr);
364→            return Err(format!("failed to reveal {path}: {stderr}"));
365→        }
366→        return Ok(());
367→    }
368→
369→    #[cfg(target_os = "linux")]
370→    {
371→        let parent = std::path::Path::new(&path)
372→            .parent()
373→            .map(|p| p.to_string_lossy().to_string())
374→            .unwrap_or_else(|| path.clone());
375→        let output = std::process::Command::new("xdg-open")
376→            .arg(&parent)
377→            .output()
378→            .map_err(|e| format!("failed to reveal: {e}"))?;
379→        if !output.status.success() {
380→            let stderr = String::from_utf8_lossy(&output.stderr);
381→            return Err(format!("failed to reveal: {stderr}"));
382→        }
383→        return Ok(());
384→    }
385→
386→    #[allow(unreachable_code)]
387→    Err("unsupported platform".to_string())
388→}
