407→fn scan_app_dir(dir: &std::path::Path, depth: usize) -> Vec<std::path::PathBuf> {
408→    let mut apps = Vec::new();
409→    let Ok(entries) = std::fs::read_dir(dir) else {
410→        return apps;
411→    };
412→
413→    for entry in entries.flatten() {
414→        let path = entry.path();
415→        if path.extension().map_or(false, |e| e == "app") {
416→            apps.push(path);
417→        } else if depth > 0 && path.is_dir() {
418→            let name = path.file_name().unwrap_or_default().to_string_lossy();
419→            if !name.starts_with('.') {
420→                apps.extend(scan_app_dir(&path, depth - 1));
421→            }
422→        }
423→    }
424→    apps
425→}
