439→fn extract_png_from_icns(icns_data: &[u8]) -> Option<Vec<u8>> {
440→    if icns_data.len() < 8 || &icns_data[0..4] != b"icns" {
441→        return None;
442→    }
443→
444→    let total_len = u32::from_be_bytes(icns_data[4..8].try_into().ok()?) as usize;
445→    let total_len = total_len.min(icns_data.len());
446→
447→    let preferred: &[&[u8; 4]] = &[
448→        b"icp5", b"icp6", b"icp4", b"ic07",
449→    ];
450→
451→    let mut offset = 8;
452→    let mut entries: Vec<(&[u8], &[u8])> = Vec::new();
453→
454→    while offset + 8 <= total_len {
455→        let type_code = &icns_data[offset..offset + 4];
456→        let entry_len = u32::from_be_bytes(icns_data[offset + 4..offset + 8].try_into().ok()?) as usize;
457→        if entry_len < 8 || offset + entry_len > total_len {
458→            break;
459→        }
460→        let data = &icns_data[offset + 8..offset + entry_len];
461→        entries.push((type_code, data));
462→        offset += entry_len;
463→    }
464→
465→    for pref in preferred {
466→        for (type_code, data) in &entries {
467→            if *type_code == pref.as_slice() && data.starts_with(&[0x89, 0x50, 0x4E, 0x47]) {
468→                return Some(data.to_vec());
469→            }
470→        }
471→    }
472→
473→    let max_fallback_size = 200_000;
474→    for (_, data) in &entries {
475→        if data.starts_with(&[0x89, 0x50, 0x4E, 0x47]) && data.len() <= max_fallback_size {
476→            return Some(data.to_vec());
477→        }
478→    }
479→
480→    None
481→}
