555→#[tauri::command(async)]
556→fn discover_applications(
557→    state: tauri::State<'_, Mutex<AppCache>>,
558→    force_refresh: bool,
559→) -> Vec<AppEntry> {
560→    if !force_refresh {
561→        if let Ok(cache) = state.lock() {
562→            if let Some(ref apps) = cache.apps {
563→                return apps.clone();
564→            }
565→        }
566→    }
567→
568→    let apps = build_app_list();
569→
570→    if let Ok(mut cache) = state.lock() {
571→        cache.apps = Some(apps.clone());
572→    }
573→
574→    apps
575→}
