577→fn is_valid_app_path(path: &std::path::Path) -> bool {
578→    let canonical = match path.canonicalize() {
579→        Ok(p) => p,
580→        Err(_) => return false,
581→    };
582→
583→    if canonical.extension().map_or(true, |e| e != "app") {
584→        return false;
585→    }
586→
587→    let mut allowed_dirs = vec![std::path::PathBuf::from("/Applications")];
588→    if let Some(home) = dirs_next::home_dir() {
589→        allowed_dirs.push(home.join("Applications"));
590→    }
591→
592→    for dir in &allowed_dirs {
593→        if let Ok(canonical_dir) = dir.canonicalize() {
594→            if canonical.starts_with(&canonical_dir) {
595→                return true;
596→            }
597→        }
598→    }
599→    false
600→}
