774→#[cfg_attr(mobile, tauri::mobile_entry_point)]
775→pub fn run() {
776→    tauri::Builder::default()
777→        .plugin(tauri_plugin_clipboard_manager::init())
778→        .plugin(tauri_plugin_shell::init())
779→        .plugin(
780→            tauri_plugin_sql::Builder::default()
781→                .add_migrations("sqlite:raycast_clone.db", db_migrations())
782→                .build(),
783→        )
784→        .manage(Mutex::new(WindowConfig::default()))
785→        .manage(Mutex::new(AppCache::default()))
786→        .invoke_handler(tauri::generate_handler![
787→            set_window_position_pref,
788→            search_files,
789→            open_file,
790→            reveal_in_finder,
791→            move_to_trash,
792→            discover_applications,
793→            launch_application
794→        ])
795→        .setup(|app| {
796→            #[cfg(desktop)]
797→            {
798→                let shortcut = Shortcut::new(Some(Modifiers::ALT), Code::Space);
799→                let window = app
800→                    .get_webview_window("main")
801→                    .expect("main window not found");
802→
803→                let window_for_blur = window.clone();
804→                window.on_window_event(move |event| {
805→                    if let tauri::WindowEvent::Focused(false) = event {
806→                        if let Err(e) = window_for_blur.hide() {
807→                            eprintln!("failed to hide on blur: {e}");
808→                        }
809→                    }
810→                });
811→
812→                #[cfg(target_os = "macos")]
813→                {
814→                    use window_vibrancy::{apply_vibrancy, NSVisualEffectMaterial};
815→                    if let Err(e) =
816→                        apply_vibrancy(&window, NSVisualEffectMaterial::HudWindow, None, None)
817→                    {
818→                        eprintln!("failed to apply vibrancy: {e}");
819→                    }
820→                }
821→
822→                position_near_top(&window);
823→
824→                start_clipboard_monitor(app.handle().clone());
825→
826→                let window_for_shortcut = window.clone();
827→                app.handle().plugin(
828→                    tauri_plugin_global_shortcut::Builder::new()
829→                        .with_handler(move |_app, scut, event| {
830→                            if scut == &shortcut && event.state() == ShortcutState::Pressed {
831→                                toggle_window(&window_for_shortcut);
832→                            }
833→                        })
834→                        .build(),
835→                )?;
836→
837→                app.global_shortcut().register(shortcut)?;
838→
839→                let show_item =
840→                    MenuItem::with_id(app, "show", "Show Raycast", true, None::<&str>)?;
841→                let clipboard_item =
842→                    MenuItem::with_id(app, "clipboard", "Clipboard History", true, None::<&str>)?;
843→                let snippets_item =
844→                    MenuItem::with_id(app, "snippets", "Snippets", true, None::<&str>)?;
845→                let settings_item =
846→                    MenuItem::with_id(app, "settings", "Settings", true, None::<&str>)?;
847→                let check_updates_item = MenuItem::with_id(
848→                    app,
849→                    "check-updates",
850→                    "Check for Updates",
851→                    true,
852→                    None::<&str>,
853→                )?;
854→                let about_item =
855→                    MenuItem::with_id(app, "about", "About Raycast Clone", true, None::<&str>)?;
856→                let quit_item = MenuItem::with_id(app, "quit", "Quit", true, None::<&str>)?;
857→
858→                let menu = Menu::with_items(
859→                    app,
860→                    &[
861→                        &show_item,
862→                        &PredefinedMenuItem::separator(app)?,
863→                        &clipboard_item,
864→                        &snippets_item,
865→                        &settings_item,
866→                        &PredefinedMenuItem::separator(app)?,
867→                        &check_updates_item,
868→                        &about_item,
869→                        &quit_item,
870→                    ],
871→                )?;
872→
873→                let window_for_menu = window.clone();
874→                let window_for_tray = window.clone();
875→
876→                TrayIconBuilder::new()
877→                    .icon(tauri::image::Image::from_bytes(include_bytes!(
878→                        "../icons/tray-icon@2x.png"
879→                    ))?)
880→                    .icon_as_template(true)
881→                    .tooltip("Raycast Clone")
882→                    .menu(&menu)
883→                    .show_menu_on_left_click(false)
884→                    .on_menu_event(move |app, event| match event.id().as_ref() {
885→                        "show" => {
886→                            show_and_focus(&window_for_menu);
887→                        }
888→                        "clipboard" | "snippets" | "settings" | "about" | "check-updates" => {
889→                            show_and_focus(&window_for_menu);
890→                            if let Err(e) =
891→                                app.emit("tray-navigate", event.id().as_ref().to_string())
892→                            {
893→                                eprintln!("failed to emit tray-navigate: {e}");
894→                            }
895→                        }
896→                        "quit" => {
897→                            app.exit(0);
898→                        }
899→                        _ => {}
900→                    })
901→                    .on_tray_icon_event(move |_tray, event| {
902→                        if let TrayIconEvent::Click {
903→                            button: MouseButton::Left,
904→                            button_state: MouseButtonState::Up,
905→                            ..
906→                        } = event
907→                        {
908→                            toggle_window(&window_for_tray);
909→                        }
910→                    })
911→                    .build(app)?;
912→            }
913→
914→            Ok(())
915→        })
916→        .run(tauri::generate_context!())
917→        .expect("error while running tauri application");
918→}
