422→function ExtensionsTab({
423→  extensions,
424→  onToggle,
425→  query,
426→}: {
427→  extensions: ExtensionEntry[];
428→  onToggle: (id: string) => void;
429→  query: string;
430→}) {
431→  const filtered = useMemo(() => {
432→    if (!query) return extensions;
433→    const lower = query.toLowerCase();
434→    return extensions.filter(
435→      ext =>
436→        ext.name.toLowerCase().includes(lower) ||
437→        ext.description.toLowerCase().includes(lower) ||
438→        ext.author.toLowerCase().includes(lower),
439→    );
440→  }, [
441→    extensions,
442→    query,
443→  ]);
444→
445→  const raycastExts = filtered.filter(ext => ext.author === 'Raycast');
446→  const communityExts = filtered.filter(ext => ext.author !== 'Raycast');
447→
448→  return (
449→    <div className="settings-view__extensions">
450→      {filtered.length === 0 ? (
451→        <EmptyState
452→          icon={<SearchEmptyIcon />}
453→          title="No Extensions Found"
454→          description="Try a different search term"
455→        />
456→      ) : (
457→        <>
458→          {raycastExts.length > 0 && (
459→            <div className="settings-section">
460→              <div className="settings-section__title">Built-in</div>
461→              {raycastExts.map(ext => (
462→                <ExtensionRow
463→                  key={ext.id}
464→                  ext={ext}
465→                  onToggle={onToggle}
466→                  showAuthor={false}
467→                />
468→              ))}
469→            </div>
470→          )}
471→          {communityExts.length > 0 && (
472→            <div className="settings-section">
473→              <div className="settings-section__title">Community</div>
474→              {communityExts.map(ext => (
475→                <ExtensionRow
476→                  key={ext.id}
