584→export function SettingsView() {
585→  const nav = useNavigation();
586→  const { preference: themePreference, setTheme } = useTheme();
587→  const { setPositionPreference } = useWindow();
588→  const [query, setQuery] = useState('');
589→  const [activeTab, setActiveTab] = useState<SettingsTab>('general');
590→  const [actionsOpen, setActionsOpen] = useState(false);
591→  const [settings, setSettings] = useState<GeneralSettings>({
592→    ...DEFAULT_SETTINGS,
593→    appearance: themePreference,
594→  });
595→  const [extensions, setExtensions] = useState<ExtensionEntry[]>(() =>
596→    MOCK_EXTENSIONS.map(ext => ({ ...ext })));
597→  const { items: hudItems, show: showHUD } = useHUD();
598→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
599→
600→  useEffect(() => {
601→    let cancelled = false;
602→    Promise.all([
603→      settingsDb.get(SETTINGS_DB_KEY),
604→      settingsDb.get(EXTENSIONS_DB_KEY),
605→    ])
606→      .then(([rawSettings, rawExtensions]) => {
607→        if (cancelled) return;
608→        const stored = parseSettings(rawSettings);
609→        if (stored) {
610→          setSettings(prev => ({
611→            ...prev,
612→            ...stored,
613→            appearance: prev.appearance,
614→          }));
615→        }
616→        const states = parseExtensionStates(rawExtensions);
617→        if (states) {
618→          setExtensions(
619→            MOCK_EXTENSIONS.map(ext => ({
620→              ...ext,
621→              enabled: states[ext.id] ?? ext.enabled,
622→            })),
623→          );
624→        }
625→      })
626→      .catch(console.error);
627→    return () => {
628→      cancelled = true;
629→    };
630→  }, []);
631→
632→  useEffect(() => {
633→    setSettings(prev => ({
634→      ...prev,
635→      appearance: themePreference,
636→    }));
637→  }, [themePreference]);
638→
639→  const handleSettingsChange = useCallback(
640→    (newSettings: GeneralSettings) => {
641→      setSettings(newSettings);
642→      settingsDb
643→        .set(SETTINGS_DB_KEY, JSON.stringify(newSettings))
644→        .catch(console.error);
645→      if (
646→        newSettings.appearance === 'dark' ||
647→        newSettings.appearance === 'light' ||
648→        newSettings.appearance === 'system'
649→      ) {
650→        setTheme(newSettings.appearance);
651→      }
652→    },
653→    [setTheme],
654→  );
655→
656→  const handleQueryChange = useCallback((value: string) => {
657→    setQuery(value);
658→  }, []);
659→
660→  const handleTabChange = useCallback((value: string) => {
661→    if (isSettingsTab(value)) {
662→      setActiveTab(value);
663→      setQuery('');
664→    }
665→  }, []);
666→
667→  const handleToggleExtension = useCallback((id: string) => {
668→    setExtensions(prev => {
669→      const next = prev.map(ext =>
670→        ext.id === id
671→          ? {
672→              ...ext,
673→              enabled: !ext.enabled,
674→            }
675→          : ext);
676→      const states: Record<string, boolean> = {};
677→      for (const ext of next) {
678→        states[ext.id] = ext.enabled;
679→      }
680→      settingsDb
681→        .set(EXTENSIONS_DB_KEY, JSON.stringify(states))
682→        .catch(console.error);
683→      return next;
684→    });
685→  }, []);
686→
687→  const handleExport = useCallback(() => {
688→    showHUD({
689→      icon: <CopyHUDIcon />,
690→      title: 'Settings Exported',
691→    });
692→  }, [showHUD]);
693→
694→  const handleImport = useCallback(() => {
695→    showHUD({
696→      icon: <CopyHUDIcon />,
697→      title: 'Settings Imported',
698→    });
699→  }, [showHUD]);
700→
701→  const handleClearCache = useCallback(() => {
702→    showHUD({
703→      icon: <CopyHUDIcon />,
704→      title: 'Cache Cleared',
