716→          <circle cx="16" cy="16" r="14" fill="currentColor" opacity="0.15" />
717→          <path
718→            d="M12 13V22M16 13V22M20 13V22M10 10H22M13 10V9C13 8.45 13.45 8 14 8H18C18.55 8 19 8.45 19 9V10"
719→            stroke="currentColor"
720→            strokeWidth="1.5"
721→            strokeLinecap="round"
722→            strokeLinejoin="round"
723→          />
724→        </svg>
