821→        ],
822→      });
823→    }
824→
825→    return sections;
826→  }, [
827→    activeTab,
828→    handleExport,
829→    handleImport,
830→    handleClearCache,
831→    handleResetAll,
832→  ]);
833→
834→  return (
835→    <>
